 "turf_rainforest", 		   [GROUND.DEEPRAINFOREST] = "turf_deeprainforest", 		   [GROUND.FIELDS] = "turf_fields", 		   [GROUND.SUBURB] = "turf_moss", 		   [GROUND.FOUNDATION] = "turf_foundation", 		   [GROUND.LAWN] = "turf_lawn",      [GROUND.COBBLEROAD] = "turf_cobbleroad", 	    [GROUND.GASJUNGLE] = "turf_gasjungle", 				 } AddComponentPostInit("terraformer", function(self)   local function SpawnTurf(turf, pt)     if turf then         local loot = SpawnPrefab(turf)         loot.Transform:SetPosition(pt.x, pt.y, pt.z)         if loot.Physics then             local angle = math.random()*2*GLOBAL.PI             loot.Physics:SetVel(2*math.cos(angle), 10, 2*math.sin(angle))         end     end   end   local _Terraform = self.Terraform   self.Terraform = function(self, pt)     if self:CanTerraformPoint(pt) == false then         return false     end     local ground = GLOBAL.GetWorld()     local original_tile_type = ground.Map:GetTileAtPoint(pt.x, pt.y, pt.z)     local ret = _Terraform(self, pt)     if ret == true then         local turf_prefab = MANGA_TURFS[original_tile_type]          if turf_prefab ~= nil then             SpawnTurf(turf_prefab, pt)          end         return true     end     return false   end    end) 	 AddComponentPostInit("groundpounder", function(self) 	table.insert(self.noTags, "groundpoundimmune") end) AddPrefabPostInit('rock1',function(inst) 	inst.components.lootdropper:AddChanceLoot('jellybug',0.2) 	inst.components.lootdropper:AddChanceLoot('slugbug',0.2) end) AddPrefabPostInit('rock2',function(inst)  	inst.components.lootdropper:AddChanceLoot('jellybug',0.25) 	inst.components.lootdropper:AddChanceLoot('slugbug',0.25) 	 	if IsDLCEnabled(CAPY_DLC) and SaveGameIndex:IsModeShipwrecked() then    inst:AddComponent("childspawner")    inst.components.childspawner.childname = "weevole"   	inst.components.childspawner:SetRegenPeriod(TUNING.TOTAL_DAY_TIME*2)   	inst.components.childspawner:SetSpawnPeriod(TUNING.TOTAL_DAY_TIME/16)    inst.components.childspawner:SetMaxChildren(2)    inst.components.childspawner:StartSpawning()  end end)   AddPrefabPostInit("killerbee",function(inst)   	inst.components.lootdropper:AddChanceLoot('bundle_blueprint', 0.04)  end) AddPrefabPostInit("gunpowder",function(inst)     inst:AddComponent("tradable") end) AddPrefabPostInit("lotus", function(inst)      inst:AddComponent("lootdropper")     inst:AddComponent("workable") 	inst.components.workable:SetWorkAction(ACTIONS.HAMMER) 	inst.components.workable:SetWorkLeft(3) 	inst.components.workable:SetOnFinishCallback(function(inst, worker)  		inst.components.lootdropper:SpawnLootPrefab("lotus_flower") 		inst.components.lootdropper:SpawnLootPrefab("lotus_flower") 		inst.components.lootdropper:SpawnLootPrefab("lotus_flower")         SpawnPrefab("collapse_small").Transform:SetPosition(inst.Transform:GetWorldPosition())         inst.SoundEmitter:PlaySound("dontstarve/wilson/pickup_reeds")         inst:Remove() 	end) 	inst.components.workable:SetOnWorkCallback(function(inst, worker)     	inst.AnimState:PushAnimation("idle") 	end)  end)  AddPrefabPostInit("lilypad", function(inst)      inst:AddComponent("lootdropper")     inst:AddComponent("workable") 	inst.components.workable:SetWorkAction(ACTIONS.HAMMER) 	inst.components.workable:SetWorkLeft(3) 	inst.components.workable:SetOnFinishCallback(function(inst, worker)          inst.components.lootdropper:DropLoot(Vector3(inst.Transform:GetWorldPosition()))         SpawnPrefab("collapse_small").Transform:SetPosition(inst.Transform:GetWorldPosition())         inst.SoundEmitter:PlaySound("dontstarve/wilson/pickup_reeds")         inst:Remove() 	end)  end)  local old_harvest_fn = ACTIONS.HARVEST.fn ACTIONS.HARVEST.fn = function(act)   if act.target.components.melter then         return act.target.components.melter:Harvest(act.doer)   end   return old_harvest_fn(act) end local function hunter(self) 	local old_spawn = self.SpawnHuntedBeast 	function self:SpawnHuntedBeast() 		local rate = 0.5  		local old_pf = self.alternate_beast_prefab 		local rc 		if math.random() < rate then 			self.alternate_beast_prefab = "ancient_herald" 			rc = old_spawn(self) 		end 		self.alternate_beast_prefab = old_pf 		return rc 	end end AddComponentPostInit('hunter', hunter) AddComponentPostInit("quaker", function(self)   function self:IsQuaking()    	return self.quake   end end) AddPlayerPostInit( function(inst)     inst:ListenForEvent("builditem", function(inst,data)     if data.item.prefab == "livinglog" then        inst.components.health:DoDelta(-20)     end    end) end) AddComponentPostInit('builder', function(self) 	local old_can = self.CanBuild 	function self:CanBuild(recname,...)     	if self.freebuildmode then         	return true     	end     	local recipe = GetRecipe(recname)     	if recipe and recipe.qqcykbz_fn and not recipe.qqcykbz_fn(self.inst) then     		return false     	end     	return old_can(self,recname,...)     end end) AddStategraphPostInit("wilson", function(sg)   local old_handler = sg.actionhandlers[ACTIONS.BUILD].deststate   sg.actionhandlers[ACTIONS.BUILD].deststate = function(inst, action)      if not inst.sg:HasStateTag('busy') then        if action.recipe and action.recipe == "livinglog" and GetPlayer().components.health.currenthealth <= 20 then         GetPlayer().components.talker:Say("血量不满足！")         return nil       end       return old_handler(inst, action)     end    end    local old_handler = sg.actionhandlers[ACTIONS.FERTILIZE].deststate   sg.actionhandlers[ACTIONS.FERTILIZE].deststate = function(inst, action)      if inst:HasTag("healonfertilize") and not action.target then       return "fertilize_short"                     else       return old_handler(inst, action)     end   end  end) AddComponentPostInit("eater", function(self)     self.healthabsorption = 1     self.hungerabsorption = 1     self.sanityabsorption = 1   function self:SetAbsorptionModifiers(health, hunger, sanity)     self.healthabsorption = health     self.hungerabsorption = hunger     self.sanityabsorption = sanity   end  function self:Eat( food )     if self:CanEat(food) then 		local stack_mult = self.eatwholestack and food.components.stackable ~= nil and food.components.stackable:StackSize() or 1         if self.inst.components.health and not self.inst:HasTag("donthealfromfood") then 			if (food.components.edible.healthvalue < 0 and self:DoFoodEffects(food) or food.components.edible.healthvalue > 0) and self.inst.components.health then                 local delta = food.components.edible:GetHealth(self.inst) * self.healthabsorption * self.healthabsorption 				self.inst.components.health:DoDelta(delta* stack_mult, nil, food.prefab)  			end         end         if self.inst.components.hunger then             local delta = food.components.edible:GetHunger(self.inst) * self.hungerabsorption             if delta ~= 0 then                 self.inst.components.hunger:DoDelta(delta * stack_mult)             end         end                  if (food.components.edible.sanityvalue < 0 and self:DoFoodEffects(food) or food.components.edible.sanityvalue > 0) and self.inst.components.sanity then             local delta = food.components.edible:GetSanity(self.inst) * self.sanityabsorption             if delta ~= 0 then                 self.inst.components.sanity:DoDelta(delta * stack_mult)             end         end         if self.inst.components.poisonable and self.inst.components.poisonable:IsPoisoned() and food.components.poisonhealer then             food.components.poisonhealer:Cure(self.inst)         end         local naughtyvalue = food.components.edible:GetNaughtiness(self.inst)         if naughtyvalue > 0 and self.inst.components.kramped then             self.inst.components.kramped:OnNaughtyAction(naughtyvalue)         end                  self.inst:PushEvent("oneat", {food = food})         if self.oneatfn then             self.oneatfn(self.inst, food)         end                  if food.components.edible then             food.components.edible:OnEaten(self.inst)         end                 if food.components.stackable and food.components.stackable.stacksize > 1 and not self.eatwholestack then             food.components.stackable:Get():Remove()         else             food:Remove()         end                  self.lasteattime = GetTime()                  self.inst:PushEvent("oneatsomething", {food = food})                  return true     end  end end) AddComponentPostInit("workable", function(self)   local function fn(target,action)       local inst=GetPlayer()       local dist = inst:GetDistanceSqToInst(target)              if dist<20*6         and inst.killedplantfn and (         (target:HasTag("renewable") or         target:HasTag("plant") or         target:HasTag("tree") or         target:HasTag("gustable") or         target:HasTag("bush"))         and         (action==ACTIONS.DIG or         action==ACTIONS.CHOP or         action==ACTIONS.HACK)         or         string.find(target.prefab, '_mushroom')         )       then           if action==ACTIONS.CHOP then             inst.killedplantfn(inst,-TUNING.SANITY_MED)           else             inst.killedplantfn(inst)           end       end   end   function self:WorkedBy(worker, numworks)     numworks = numworks or 1     self.workleft = self.workleft - numworks     self.lastworktime = GetTime()     worker:PushEvent("working", {target = self.inst})     self.inst:PushEvent("worked", {worker = worker, workleft = self.workleft})     if self.onwork then         self.onwork(self.inst, worker, self.workleft)     end     if self.workleft <= 0 then                 if self.onfinish then self.onfinish(self.inst, worker) end                 self.inst:PushEvent("workfinished")         worker:PushEvent("finishedwork", {target = self.inst, action = self.action})         fn(self.inst,self.action)     end   end end) AddPlayerPostInit( function(inst)      inst:ListenForEvent("picksomething", function(inst, data)     if data.object and inst.killedplantfn then       if data.object.prefab=="flower" then         inst.killedplantfn(inst,-TUNING.SANITY_SMALL)       elseif data.object.prefab=="flower_evil" then         inst.killedplantfn(inst)       end     end   end) end) AddComponentPostInit("fertilizer", function(self)   function self:CollectInventoryActions(doer, actions)     if doer:HasTag("healonfertilize") and self.planthealing then         table.insert(actions, ACTIONS.FERTILIZE)     end   end end) local old_fertilize_fn = ACTIONS.FERTILIZE.fn ACTIONS.FERTILIZE.fn = function(act) 	if not act.target and act.doer:HasTag("healonfertilize") and act.invobject then 		if  act.doer.components.health then 		    act.doer.components.health:DoDelta(2,false,"fertilize") 		     		    if act.invobject.components.stackable and act.invobject.components.stackable.stacksize > 1 then 		        act.invobject.components.stackable:Get():Remove() 		    else 		    	if act.invobject.components.finiteuses then 		    		act.invobject.components.finiteuses:Use(2) 		    	else 		        	act.invobject:Remove() 		    	end 		    end 		    return true 		end 	end   return old_fertilize_fn(act) end local function healer(inst)     inst.components.fertilizer.planthealing = true end AddPrefabPostInit( "guano", healer) AddPrefabPostInit( "poop", healer) AddPrefabPostInit( "fertilizer", healer) local function fn(inst,pt,deployer)   local plant = string.find(inst.prefab, 'dug_') or                string.find(inst.prefab, 'seeds') or                string.find(inst.prefab, 'butterfly') or                inst.growtime   if plant and deployer:HasTag("plantkin") then     if deployer.growplantfn then       deployer.growplantfn(deployer)     end          local ents = TheSim:FindEntities(pt.x, pt.y, pt.z, 1, nil,nil, {"renewable", "plant", "tree", "gustable", "bush", })     for i, v in ipairs(ents) do         if v and  v.components.pickable then 		    v.components.pickable.cycles_left = v.components.pickable.max_cycles 		    v.components.pickable:MakeEmpty()         end     end   end end AddComponentPostInit("deployable", function(self)   function self:Deploy(pt, deployer)     if not self.test or self.test(self.inst, pt, deployer) then 		if self.ondeploy then 	        self.ondeploy(self.inst, pt, deployer) 		end 		fn(self.inst,pt,deployer) 		return true 	end   end end) local function cropfn(inst) function inst:Harvest(harvester)     if self.matured or self.withered then         local product = nil         if self.grower and self.grower:HasTag("fire") or self.inst:HasTag("fire") then             local temp = SpawnPrefab(self.product_prefab)             if temp.components.cookable and temp.components.cookable.product then                 product = SpawnPrefab(temp.components.cookable.product)             else                 product = SpawnPrefab("seeds_cooked")             end             temp:Remove()         else             product = SpawnPrefab(self.product_prefab)         end         if product then             local targetMoisture = 0             if self.inst.components.moisturelistener then                 targetMoisture = self.inst.components.moisturelistener:GetMoisture()             elseif self.inst.components.moisture then                 targetMoisture = self.inst.components.moisture:GetMoisture()             else                 targetMoisture = GetWorld().components.moisturemanager:GetWorldMoisture()             end                          product.targetMoisture = targetMoisture             product:DoTaskInTime(2*FRAMES, function()                 if product.components.moisturelistener then                      product.components.moisturelistener.moisture = product.targetMoisture                     product.targetMoisture = nil                     product.components.moisturelistener:DoUpdate()                 end             end)         end         harvester.components.inventory:GiveItem(product)         ProfileStatsAdd("grown_"..product.prefab)                   self.matured = false         self.withered = false         self.inst:RemoveTag("withered")         self.growthpercent = 0         self.product_prefab = nil         if self.grower and self.grower.components and self.grower.components.grower then         self.grower.components.grower:RemoveCrop(self.inst)         else         self.inst:Remove()         end         self.grower = nil                  return true     end   end end AddComponentPostInit("crop", cropfn) local function ondeploy(inst, pt, deployer)         local prefab = nil     if inst.components.plantable.product and type(inst.components.plantable.product) == "function" then         prefab = inst.components.plantable.product(inst)     else         prefab = inst.components.plantable.product or inst.prefab     end     local plant1 = SpawnPrefab("plant_normal")          plant1.components.crop:StartGrowing(prefab, inst.components.plantable.growtime, plant1)     plant1.Transform:SetPosition(pt.x,0,pt.z)     inst.SoundEmitter:PlaySound("dontstarve/common/craftable/farm_basic")     inst:Remove() end local notags = {'NOBLOCK', 'player', 'FX'} local function test_deploy(inst, pt)     if not GetPlayer():HasTag("plantkin") then         return false     end     local tiletype = GetGroundTypeAtPosition(pt)     local ground_OK = tiletype ~= GROUND.ROCKY and tiletype ~= GROUND.ROAD and tiletype ~= GROUND.IMPASSABLE and tiletype ~= GROUND.INTERIOR and                         tiletype ~= GROUND.UNDERROCK and tiletype ~= GROUND.WOODFLOOR and tiletype ~= GROUND.MAGMAFIELD and                          tiletype ~= GROUND.CARPET and tiletype ~= GROUND.CHECKER and                          tiletype ~= GROUND.ASH and tiletype ~= GROUND.VOLCANO and tiletype ~= GROUND.VOLCANO_ROCK and tiletype ~= GROUND.BRICK_GLOW and                         tiletype ~= GROUND.FOUNDATION and tiletype ~= GROUND.COBBLEROAD and                          tiletype < GROUND.UNDERGROUND          local ground = GetWorld()     if ground.Map:IsWater(tiletype) then          ground_OK = false      end           if ground_OK then         local ents = TheSim:FindEntities(pt.x,pt.y,pt.z, 4, nil, notags)          local min_spacing = inst.components.deployable.min_spacing or 2         for k, v in pairs(ents) do             if v ~= inst and v:IsValid() and v.entity:IsVisible() and not v.components.placer and v.parent == nil then                 if distsq( Vector3(v.Transform:GetWorldPosition()), pt) < min_spacing*min_spacing then                     return false                 end             end         end                  return true     end     return false end local function become_plantable(inst)     inst:AddTag("plant")     inst:AddComponent("deployable")     inst.components.deployable.userrequiredtags = {"plantkin"}     inst.components.deployable.ondeploy = ondeploy     inst.components.deployable.test = test_deploy     inst.components.deployable.min_spacing = 2         inst.components.deployable.onlydeploybyplantkin = true end local seeds ={ 		"grapricot_seeds", "limon_seeds", "tomango_seeds", "yamion_seeds", 		"garleek_seeds", "rutabeeta_seeds", "guavacado_seeds", "zucchilli_seeds", 		"sweet_potato_seeds","watermelon_seeds","dragonfruit_seeds","pomegranate_seeds", 		"durian_seeds","eggplant_seeds","pumpkin_seeds","corn_seeds", 		"carrot_seeds","seeds", 	} for k, seed in pairs(seeds) do 	AddPrefabPostInit( seed, become_plantable) end AddComponentPostInit("placer", function(self)   local old_OnUpdate = self.OnUpdate   function self:OnUpdate(dt)   	 if self.invobject and self.invobject.components.deployable.onlydeploybyplantkin and not GetPlayer():HasTag("plantkin") then 	    	self.inst:Hide()    	else 		    self.inst:Show() 	    	local color = self.can_build and Vector3(.25, .75, .25) or Vector3(.75, .25, .25)		 	    	self.inst.AnimState:SetAddColour(color.x, color.y, color.z, 1)    	end    	return old_OnUpdate(self,dt)   end end) 